UPDATE public.books SET description = 'Peer Gynt is a charming but lazy and arrogant peasant youth who leaves home to seek his fortune. Confident of success, he has one disastrous adventure after another. In one, he attends the wedding of a wealthy young woman he himself might have married. There he meets Solveig, who falls in love with him.' WHERE id = '65cc36b1-ad6a-4e8a-9a80-778b3a87bb6f';